#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int K; scanf("%d",&K);
        bool ok=true;
        char buf[105];
        for(int i=0;i<K;i++){
            scanf("%s",buf);
            bool hasLow=false, hasUp=false;
            for(int j=0;buf[j];j++){
                char c=buf[j];
                if(c>='a' && c<='z'){
                    if(c<'a' || c>'m'){ok=false;break;}
                    hasLow=true;
                }else if(c>='A' && c<='Z'){
                    if(c<'N' || c>'Z'){ok=false;break;}
                    hasUp=true;
                }else{ok=false;break;}
                if(hasLow && hasUp){ok=false;break;}
            }
        }
        printf(ok?"YES\n":"NO\n");
    }
    return 0;
}

