import sys

def solve():
    data=sys.stdin.read().split()
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        K=int(next(it))
        ok=True
        for _ in range(K):
            word=next(it)
            has_low=False
            has_up=False
            for ch in word:
                if 'a'<=ch<='z':
                    if ch<'a' or ch>'m':
                        ok=False
                        break
                    has_low=True
                elif 'A'<=ch<='Z':
                    if ch<'N' or ch>'Z':
                        ok=False
                        break
                    has_up=True
                else:
                    ok=False
                    break
                if has_low and has_up:
                    ok=False
                    break
            # continue reading remaining words even if ok became False
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    solve()

